package generators

import (
	"fmt"
	"io"
	"path/filepath"
	"strings"

	"k8s.io/gengo/v2"
	"k8s.io/gengo/v2/generator"
	"k8s.io/gengo/v2/namer"
	"k8s.io/gengo/v2/types"
	"k8s.io/klog/v2"
	"k8s.io/kube-openapi/pkg/generators/apidefinitions"
)

const (
	tagModelPackage = "k8s:openapi-model-package"
)

func extractOpenAPISchemaNamePackage(comments []string) (string, error) {
	v, err := singularTag(tagModelPackage, comments)
	if v == nil || err != nil {
		return "", err
	}
	return v.Value, nil
}

// resolvePackageModelPackage returns the OpenAPI model package for pkg.
//
// The package's model package is derived from two yaml files:
//   - apiversion.yaml in pkg's directory provides the version,
//   - apigroup.yaml in the parent directory provides spec.modelPackage,
//
// joined as "<spec.modelPackage>.<version>" (e.g. "io.k8s.api.apps" + "v1"
// → "io.k8s.api.apps.v1").
//
// The legacy +k8s:openapi-model-package= tag, if present, must agree with
// the derived value; an empty result means the package opts out of openapi
// model naming.
func resolvePackageModelPackage(pkg *types.Package) (string, error) {
	tagPackage, err := extractOpenAPISchemaNamePackage(pkg.Comments)
	if err != nil {
		return "", err
	}
	apiVersion, err := apidefinitions.LoadAPIVersion(pkg.Dir)
	if err != nil {
		return "", err
	}
	if apiVersion == nil {
		// No apiversion.yaml: fall back to whatever the tag says (possibly "").
		return tagPackage, nil
	}
	parentDir := filepath.Dir(pkg.Dir)
	apiGroup, err := apidefinitions.LoadAPIGroup(parentDir)
	if err != nil {
		return "", err
	}
	if apiGroup == nil {
		if tagPackage != "" {
			return "", fmt.Errorf("in package %s: %s declares +k8s:openapi-model-package=%q but no apigroup.yaml is present in the parent directory %s to derive a model package",
				pkg.Dir, filepath.Join(pkg.Dir, "doc.go"), tagPackage, parentDir)
		}
		return "", nil
	}
	derived := apiGroup.ModelPackageFor(apiVersion.VersionFromName())
	if tagPackage != "" && tagPackage != derived {
		return "", fmt.Errorf("in package %s: parent apigroup.yaml derives model package %q for version %q but +k8s:openapi-model-package tag is %q. Please make them match or remove the tag.",
			pkg.Dir, derived, apiVersion.VersionFromName(), tagPackage)
	}
	return derived, nil
}

func singularTag(tagName string, comments []string) (*gengo.Tag, error) {
	tags, err := gengo.ExtractFunctionStyleCommentTags("+", []string{tagName}, comments)
	if err != nil {
		return nil, err
	}
	if len(tags) == 0 {
		return nil, nil
	}
	if len(tags) > 1 {
		return nil, fmt.Errorf("multiple %s tags found", tagName)
	}
	tag := tags[tagName]
	if len(tag) == 0 {
		return nil, nil
	}
	if len(tag) > 1 {
		klog.V(5).Infof("multiple %s tags found, using the first one", tagName)
	}
	value := tag[0]
	return &value, nil
}

// genSchemaName produces a file with autogenerated openapi schema name functions.
type genSchemaName struct {
	generator.GoGenerator
	targetPackage            string
	imports                  namer.ImportTracker
	typesForInit             []*types.Type
	openAPISchemaNamePackage string
}

// NewSchemaNameGen creates a generator
func NewSchemaNameGen(outputFilename, targetPackage string, openAPISchemaNamePackage string) generator.Generator {
	return &genSchemaName{
		GoGenerator: generator.GoGenerator{
			OutputFilename: outputFilename,
		},
		targetPackage:            targetPackage,
		imports:                  generator.NewImportTracker(),
		typesForInit:             make([]*types.Type, 0),
		openAPISchemaNamePackage: openAPISchemaNamePackage,
	}
}

func (g *genSchemaName) Namers(c *generator.Context) namer.NameSystems {
	return namer.NameSystems{
		"public": namer.NewPublicNamer(1),
		"local":  namer.NewPublicNamer(0),
		"raw":    namer.NewRawNamer("", nil),
	}
}

func (g *genSchemaName) Filter(c *generator.Context, t *types.Type) bool {
	// Filter out types not being processed or not copyable within the package.
	if !isSchemaNameType(t) {
		klog.V(2).Infof("Type %v is not a valid target for OpenAPI schema name", t)
		return false
	}
	g.typesForInit = append(g.typesForInit, t)
	return true
}

// isSchemaNameType indicates whether or not a type could be used to serve an API.
func isSchemaNameType(t *types.Type) bool {
	// Filter out private types.
	if namer.IsPrivateGoName(t.Name.Name) {
		return false
	}

	for t.Kind == types.Alias {
		t = t.Underlying
	}

	if t.Kind != types.Struct {
		return false
	}
	return true
}

func (g *genSchemaName) isOtherPackage(pkg string) bool {
	if pkg == g.targetPackage {
		return false
	}
	if strings.HasSuffix(pkg, ""+g.targetPackage+"") {
		return false
	}
	return true
}

func (g *genSchemaName) Imports(c *generator.Context) (imports []string) {
	importLines := []string{}
	for _, singleImport := range g.imports.ImportLines() {
		if g.isOtherPackage(singleImport) {
			importLines = append(importLines, singleImport)
		}
	}
	return importLines
}

func (g *genSchemaName) Init(c *generator.Context, w io.Writer) error {
	return nil
}

func (g *genSchemaName) GenerateType(c *generator.Context, t *types.Type, w io.Writer) error {
	klog.V(3).Infof("Generating openapi schema name for type %v", t)

	openAPISchemaNamePackage := g.openAPISchemaNamePackage
	v, err := singularTag(tagModelPackage, t.CommentLines)
	if err != nil {
		return fmt.Errorf("type %v: invalid %s:%v", t.Name, tagModelPackage, err)
	}
	if v != nil && v.Value != "" {
		openAPISchemaNamePackage = v.Value
	}

	if openAPISchemaNamePackage == "" {
		return nil
	}

	schemaName := openAPISchemaNamePackage + "." + t.Name.Name

	a := map[string]interface{}{
		"type":       t,
		"schemaName": schemaName,
	}

	sw := generator.NewSnippetWriter(w, c, "$", "$")

	sw.Do("// OpenAPIModelName returns the OpenAPI model name for this type.\n", a)
	sw.Do("func (in $.type|local$) OpenAPIModelName() string {\n", a)
	sw.Do("\treturn \"$.schemaName$\"\n", a)
	sw.Do("}\n\n", nil)

	return sw.Error()
}
